    internal LedgerDimensionAccount ubsSubBillDeferralGetDefaultLedgerDimensionAccount()
    {
        LedgerDimensionAccount          ledgerDimensionAccount;
        LedgerDimensionDefaultAccount   ledgerDimensionDefaultAccount;
            
        if (this.PurchLineRecId)
        {
            ledgerDimensionDefaultAccount = this.purchLine().ledgerDimensionConsumption();
        }
        else
        {
            if (this.isCategoryBased() || !this.inventoried())
            {
                ledgerDimensionDefaultAccount = this.accountItemLedgerDimension(InventAccountType::PurchExpense);
            }
            else if (InventTable::modelGroupByItemId(this.ItemId).PostOnhandFinancial)
            {
                ledgerDimensionDefaultAccount = this.accountItemLedgerDimension(InventAccountType::PurchReceipt);
            }
            else
            {
                ledgerDimensionDefaultAccount = this.accountItemLedgerDimension(InventAccountType::PurchConsump);
            }
        }
            
        if (ledgerDimensionDefaultAccount)
        {
            ledgerDimensionAccount = LedgerDimensionFacade::serviceCreateLedgerDimension(ledgerDimensionDefaultAccount, this.DefaultDimension);
        }

        return ledgerDimensionAccount;
    }
